 80→export const SearchMenu = () => {
 81→  const app = useApp();
 82→  const setAppState = useExcalidrawSetAppState();
 83→
 84→  const searchInputRef = useRef<HTMLInputElement>(null);
 85→
 86→  const [inputValue, setInputValue] = useAtom(searchQueryAtom);
 87→  const searchQuery = inputValue.trim() as SearchQuery;
 88→
 89→  const [isSearching, setIsSearching] = useState(false);
 90→
 91→  const [searchMatches, setSearchMatches] = useState<SearchMatches>({
 92→    nonce: null,
 93→    items: [],
 94→  });
 95→  const searchedQueryRef = useRef<SearchQuery | null>(null);
 96→  const lastSceneNonceRef = useRef<number | undefined>(undefined);
 97→
 98→  const [focusIndex, setFocusIndex] = useAtom(searchItemInFocusAtom);
 99→  const elementsMap = app.scene.getNonDeletedElementsMap();
100→
101→  useEffect(() => {
102→    if (isSearching) {
103→      return;
104→    }
105→    if (
106→      searchQuery !== searchedQueryRef.current ||
107→      app.scene.getSceneNonce() !== lastSceneNonceRef.current
108→    ) {
109→      searchedQueryRef.current = null;
110→      handleSearch(searchQuery, app, (matchItems, index) => {
111→        setSearchMatches({
112→          nonce: randomInteger(),
113→          items: matchItems,
114→        });
115→        searchedQueryRef.current = searchQuery;
116→        lastSceneNonceRef.current = app.scene.getSceneNonce();
117→        setAppState({
118→          searchMatches: matchItems.length
119→            ? {
120→                focusedId: null,
121→                matches: matchItems.map((searchMatch) => ({
122→                  id: searchMatch.element.id,
123→                  focus: false,
124→                  matchedLines: searchMatch.matchedLines,
125→                })),
126→              }
127→            : null,
128→        });
129→      });
130→    }
131→  }, [
132→    isSearching,
133→    searchQuery,
134→    elementsMap,
135→    app,
136→    setAppState,
137→    setFocusIndex,
138→    lastSceneNonceRef,
139→  ]);
140→
141→  const goToNextItem = () => {
142→    if (searchMatches.items.length > 0) {
143→      setFocusIndex((focusIndex) => {
144→        if (focusIndex === null) {
145→          return 0;
146→        }
147→
148→        return (focusIndex + 1) % searchMatches.items.length;
149→      });
150→    }
151→  };
152→
153→  const goToPreviousItem = () => {
154→    if (searchMatches.items.length > 0) {
155→      setFocusIndex((focusIndex) => {
156→        if (focusIndex === null) {
157→          return 0;
158→        }
159→
160→        return focusIndex - 1 < 0
161→          ? searchMatches.items.length - 1
162→          : focusIndex - 1;
163→      });
164→    }
165→  };
166→
167→  useEffect(() => {
168→    setAppState((state) => {
169→      if (!state.searchMatches) {
170→        return null;
171→      }
172→
173→      const focusedId =
174→        focusIndex !== null
175→          ? state.searchMatches?.matches[focusIndex]?.id || null
176→          : null;
177→
178→      return {
179→        searchMatches: {
180→          focusedId,
181→          matches: state.searchMatches.matches.map((match, index) => {
182→            if (index === focusIndex) {
183→              return { ...match, focus: true };
184→            }
185→            return { ...match, focus: false };
186→          }),
187→        },
188→      };
189→    });
190→  }, [focusIndex, setAppState]);
191→
192→  useEffect(() => {
193→    if (searchMatches.items.length > 0 && focusIndex !== null) {
194→      const match = searchMatches.items[focusIndex];
195→
196→      if (match) {
197→        const zoomValue = app.state.zoom.value;
198→
199→        const matchAsElement = newTextElement({
200→          text: match.searchQuery,
201→          x: match.element.x + (match.matchedLines[0]?.offsetX ?? 0),
202→          y: match.element.y + (match.matchedLines[0]?.offsetY ?? 0),
203→          width: match.matchedLines[0]?.width,
204→          height: match.matchedLines[0]?.height,
205→          fontSize: isFrameLikeElement(match.element)
206→            ? FRAME_STYLE.nameFontSize
207→            : match.element.fontSize,
208→          fontFamily: isFrameLikeElement(match.element)
209→            ? FONT_FAMILY.Assistant
210→            : match.element.fontFamily,
211→        });
212→
213→        const FONT_SIZE_LEGIBILITY_THRESHOLD = 14;
214→
215→        const fontSize = matchAsElement.fontSize;
216→        const isTextTiny =
217→          fontSize * zoomValue < FONT_SIZE_LEGIBILITY_THRESHOLD;
218→
219→        if (
220→          !isElementCompletelyInViewport(
221→            [matchAsElement],
222→            app.canvas.width / window.devicePixelRatio,
223→            app.canvas.height / window.devicePixelRatio,
224→            {
225→              offsetLeft: app.state.offsetLeft,
226→              offsetTop: app.state.offsetTop,
227→              scrollX: app.state.scrollX,
228→              scrollY: app.state.scrollY,
229→              zoom: app.state.zoom,
230→            },
231→            app.scene.getNonDeletedElementsMap(),
232→            app.getEditorUIOffsets(),
233→          ) ||
234→          isTextTiny
235→        ) {
236→          let zoomOptions: Parameters<AppClassProperties["scrollToContent"]>[1];
237→
238→          if (isTextTiny) {
239→            if (fontSize >= FONT_SIZE_LEGIBILITY_THRESHOLD) {
240→              zoomOptions = { fitToContent: true };
241→            } else {
242→              zoomOptions = {
243→                fitToViewport: true,
244→                // calculate zoom level to make the fontSize ~equal to FONT_SIZE_THRESHOLD, rounded to nearest 10%
245→                maxZoom: round(FONT_SIZE_LEGIBILITY_THRESHOLD / fontSize, 1),
246→              };
247→            }
248→          } else {
249→            zoomOptions = { fitToContent: true };
250→          }
251→
252→          app.scrollToContent(matchAsElement, {
253→            animate: true,
254→            duration: 300,
255→            ...zoomOptions,
256→            canvasOffsets: app.getEditorUIOffsets(),
257→          });
258→        }
259→      }
260→    }
261→  }, [focusIndex, searchMatches, app]);
262→
263→  useEffect(() => {
264→    return () => {
265→      setFocusIndex(null);
266→      searchedQueryRef.current = null;
267→      lastSceneNonceRef.current = undefined;
268→      setAppState({
269→        searchMatches: null,
270→      });
271→      setIsSearching(false);
272→    };
273→  }, [setAppState, setFocusIndex]);
274→
275→  const stableState = useStable({
276→    goToNextItem,
277→    goToPreviousItem,
278→    searchMatches,
279→  });
280→
281→  useEffect(() => {
282→    const eventHandler = (event: KeyboardEvent) => {
283→      if (
284→        event.key === KEYS.ESCAPE &&
285→        !app.state.openDialog &&
286→        !app.state.openPopup
287→      ) {
288→        event.preventDefault();
289→        event.stopPropagation();
290→        setAppState({
291→          openSidebar: null,
292→        });
293→        return;
294→      }
295→
296→      if (event[KEYS.CTRL_OR_CMD] && event.key === KEYS.F) {
297→        event.preventDefault();
298→        event.stopPropagation();
299→
300→        if (app.state.openDialog) {
301→          return;
302→        }
303→
304→        if (!searchInputRef.current?.matches(":focus")) {
305→          if (app.state.openDialog) {
306→            setAppState({
307→              openDialog: null,
308→            });
309→          }
310→          searchInputRef.current?.focus();
311→          searchInputRef.current?.select();
312→        }
313→      }
314→
315→      if (
316→        event.target instanceof HTMLElement &&
317→        event.target.closest(".layer-ui__search")
318→      ) {
319→        if (stableState.searchMatches.items.length) {
320→          if (event.key === KEYS.ENTER) {
321→            event.stopPropagation();
322→            stableState.goToNextItem();
323→          }
324→
325→          if (event.key === KEYS.ARROW_UP) {
326→            event.stopPropagation();
327→            stableState.goToPreviousItem();
328→          } else if (event.key === KEYS.ARROW_DOWN) {
329→            event.stopPropagation();
330→            stableState.goToNextItem();
331→          }
332→        }
333→      }
334→    };
335→
336→    // `capture` needed to prevent firing on initial open from App.tsx,
337→    // as well as to handle events before App ones
338→    return addEventListener(window, EVENT.KEYDOWN, eventHandler, {
339→      capture: true,
340→      passive: false,
341→    });
342→  }, [setAppState, stableState, app]);
343→
344→  const matchCount = `${searchMatches.items.length} ${
345→    searchMatches.items.length === 1
346→      ? t("search.singleResult")
347→      : t("search.multipleResults")
348→  }`;
349→
350→  return (
351→    <div className="layer-ui__search">
352→      <div className="layer-ui__search-header">
353→        <TextField
354→          className={CLASSES.SEARCH_MENU_INPUT_WRAPPER}
355→          value={inputValue}
356→          ref={searchInputRef}
357→          placeholder={t("search.placeholder")}
358→          icon={searchIcon}
359→          onChange={(value) => {
360→            setInputValue(value);
361→            setIsSearching(true);
362→            const searchQuery = value.trim() as SearchQuery;
363→            handleSearch(searchQuery, app, (matchItems, index) => {
364→              setSearchMatches({
365→                nonce: randomInteger(),
366→                items: matchItems,
367→              });
368→              setFocusIndex(index);
369→              searchedQueryRef.current = searchQuery;
370→              lastSceneNonceRef.current = app.scene.getSceneNonce();
371→              setAppState({
372→                searchMatches: matchItems.length
373→                  ? {
374→                      focusedId: null,
375→                      matches: matchItems.map((searchMatch) => ({
376→                        id: searchMatch.element.id,
377→                        focus: false,
378→                        matchedLines: searchMatch.matchedLines,
379→                      })),
380→                    }
381→                  : null,
382→              });
383→
384→              setIsSearching(false);
385→            });
386→          }}
387→          selectOnRender
388→        />
389→      </div>
390→
391→      <div className="layer-ui__search-count">
392→        {searchMatches.items.length > 0 && (
393→          <>
394→            {focusIndex !== null && focusIndex > -1 ? (
395→              <div>
396→                {focusIndex + 1} / {matchCount}
397→              </div>
398→            ) : (
399→              <div>{matchCount}</div>
400→            )}
401→            <div className="result-nav">
402→              <Button
403→                onSelect={() => {
404→                  goToNextItem();
405→                }}
406→                className="result-nav-btn"
407→              >
408→                {collapseDownIcon}
409→              </Button>
410→              <Button
411→                onSelect={() => {
412→                  goToPreviousItem();
413→                }}
414→                className="result-nav-btn"
415→              >
416→                {upIcon}
417→              </Button>
418→            </div>
419→          </>
420→        )}
421→
422→        {searchMatches.items.length === 0 &&
423→          searchQuery &&
424→          searchedQueryRef.current && (
425→            <div style={{ margin: "1rem auto" }}>{t("search.noMatch")}</div>
426→          )}
427→      </div>
428→
429→      <MatchList
430→        matches={searchMatches}
431→        onItemClick={setFocusIndex}
432→        focusIndex={focusIndex}
433→        searchQuery={searchQuery}
434→      />
435→    </div>
436→  );
437→};
438→
439→const ListItem = (props: {
440→  preview: SearchMatchItem["preview"];
441→  searchQuery: SearchQuery;
442→  highlighted: boolean;
443→  onClick?: () => void;
444→}) => {
445→  const preview = [
446→    props.preview.moreBefore ? "..." : "",
447→    props.preview.previewText.slice(0, props.preview.indexInSearchQuery),
448→    props.preview.previewText.slice(
449→      props.preview.indexInSearchQuery,
450→      props.preview.indexInSearchQuery + props.searchQuery.length,
451→    ),
452→    props.preview.previewText.slice(
453→      props.preview.indexInSearchQuery + props.searchQuery.length,
454→    ),
455→    props.preview.moreAfter ? "..." : "",
456→  ];
457→
458→  return (
459→    <div
460→      tabIndex={-1}
461→      className={clsx("layer-ui__result-item", {
462→        active: props.highlighted,
463→      })}
464→      onClick={props.onClick}
465→      ref={(ref) => {
466→        if (props.highlighted) {
467→          ref?.scrollIntoView({ behavior: "auto", block: "nearest" });
468→        }
469→      }}
470→    >
471→      <div className="preview-text">
472→        {preview.flatMap((text, idx) => (
473→          <Fragment key={idx}>{idx === 2 ? <b>{text}</b> : text}</Fragment>
474→        ))}
475→      </div>
476→    </div>
477→  );
478→};
479→
480→interface MatchListProps {
481→  matches: SearchMatches;
482→  onItemClick: (index: number) => void;
483→  focusIndex: number | null;
484→  searchQuery: SearchQuery;
485→}
486→
487→const MatchListBase = (props: MatchListProps) => {
488→  const frameNameMatches = useMemo(
489→    () =>
490→      props.matches.items.filter((match) => isFrameLikeElement(match.element)),
491→    [props.matches],
492→  );
493→
494→  const textMatches = useMemo(
495→    () => props.matches.items.filter((match) => isTextElement(match.element)),
496→    [props.matches],
497→  );
498→
499→  return (
500→    <div>
501→      {frameNameMatches.length > 0 && (
502→        <div className="layer-ui__search-result-container">
503→          <div className="layer-ui__search-result-title">
504→            <div className="title-icon">{frameToolIcon}</div>
505→            <div>{t("search.frames")}</div>
506→          </div>
507→          {frameNameMatches.map((searchMatch, index) => (
508→            <ListItem
509→              key={searchMatch.element.id + searchMatch.index}
510→              searchQuery={props.searchQuery}
511→              preview={searchMatch.preview}
512→              highlighted={index === props.focusIndex}
513→              onClick={() => props.onItemClick(index)}
514→            />
515→          ))}
516→
517→          {textMatches.length > 0 && <div className="layer-ui__divider" />}
518→        </div>
519→      )}
520→
521→      {textMatches.length > 0 && (
522→        <div className="layer-ui__search-result-container">
523→          <div className="layer-ui__search-result-title">
524→            <div className="title-icon">{TextIcon}</div>
525→            <div>{t("search.texts")}</div>
526→          </div>
527→          {textMatches.map((searchMatch, index) => (
528→            <ListItem
529→              key={searchMatch.element.id + searchMatch.index}
530→              searchQuery={props.searchQuery}
531→              preview={searchMatch.preview}
532→              highlighted={index + frameNameMatches.length === props.focusIndex}
533→              onClick={() => props.onItemClick(index + frameNameMatches.length)}
534→            />
535→          ))}
536→        </div>
537→      )}
538→    </div>
539→  );
540→};
541→
542→const areEqual = (prevProps: MatchListProps, nextProps: MatchListProps) => {
543→  return (
544→    prevProps.matches.nonce === nextProps.matches.nonce &&
545→    prevProps.focusIndex === nextProps.focusIndex
546→  );
547→};
548→
549→const MatchList = memo(MatchListBase, areEqual);
550→
551→const getMatchPreview = (
552→  text: string,
553→  index: number,
554→  searchQuery: SearchQuery,
555→) => {
556→  const WORDS_BEFORE = 2;
557→  const WORDS_AFTER = 5;
558→
559→  const substrBeforeQuery = text.slice(0, index);
560→  const wordsBeforeQuery = substrBeforeQuery.split(/\s+/);
561→  // text = "small", query = "mall", not complete before
562→  // text = "small", query = "smal", complete before
563→  const isQueryCompleteBefore = substrBeforeQuery.endsWith(" ");
564→  const startWordIndex =
565→    wordsBeforeQuery.length -
566→    WORDS_BEFORE -
567→    1 -
568→    (isQueryCompleteBefore ? 0 : 1);
569→  let wordsBeforeAsString =
570→    wordsBeforeQuery.slice(startWordIndex <= 0 ? 0 : startWordIndex).join(" ") +
571→    (isQueryCompleteBefore ? " " : "");
572→
573→  const MAX_ALLOWED_CHARS = 20;
574→
575→  wordsBeforeAsString =
576→    wordsBeforeAsString.length > MAX_ALLOWED_CHARS
577→      ? wordsBeforeAsString.slice(-MAX_ALLOWED_CHARS)
578→      : wordsBeforeAsString;
579→
580→  const substrAfterQuery = text.slice(index + searchQuery.length);
581→  const wordsAfter = substrAfterQuery.split(/\s+/);
582→  // text = "small", query = "mall", complete after
583→  // text = "small", query = "smal", not complete after
584→  const isQueryCompleteAfter = !substrAfterQuery.startsWith(" ");
585→  const numberOfWordsToTake = isQueryCompleteAfter
586→    ? WORDS_AFTER + 1
587→    : WORDS_AFTER;
588→  const wordsAfterAsString =
589→    (isQueryCompleteAfter ? "" : " ") +
590→    wordsAfter.slice(0, numberOfWordsToTake).join(" ");
591→
592→  return {
593→    indexInSearchQuery: wordsBeforeAsString.length,
594→    previewText: wordsBeforeAsString + searchQuery + wordsAfterAsString,
595→    moreBefore: startWordIndex > 0,
596→    moreAfter: wordsAfter.length > numberOfWordsToTake,
597→  };
598→};
599→
600→const normalizeWrappedText = (
601→  wrappedText: string,
602→  originalText: string,
603→): string => {
604→  const wrappedLines = wrappedText.split("\n");
605→  const normalizedLines: string[] = [];
606→  let originalIndex = 0;
607→
608→  for (let i = 0; i < wrappedLines.length; i++) {
609→    let currentLine = wrappedLines[i];
610→    const nextLine = wrappedLines[i + 1];
611→
612→    if (nextLine) {
613→      const nextLineIndexInOriginal = originalText.indexOf(
614→        nextLine,
615→        originalIndex,
616→      );
617→
618→      if (nextLineIndexInOriginal > currentLine.length + originalIndex) {
619→        let j = nextLineIndexInOriginal - (currentLine.length + originalIndex);
620→
621→        while (j > 0) {
622→          currentLine += " ";
623→          j--;
624→        }
625→      }
626→    }
627→
628→    normalizedLines.push(currentLine);
629→    originalIndex = originalIndex + currentLine.length;
630→  }
631→
632→  return normalizedLines.join("\n");
633→};
634→
635→const getMatchedLines = (
636→  textElement: ExcalidrawTextElement,
637→  searchQuery: SearchQuery,
638→  index: number,
639→) => {
640→  const normalizedText = normalizeWrappedText(
641→    textElement.text,
642→    textElement.originalText,
643→  );
644→
645→  const lines = normalizedText.split("\n");
646→
647→  const lineIndexRanges = [];
648→  let currentIndex = 0;
649→  let lineNumber = 0;
650→
651→  for (const line of lines) {
652→    const startIndex = currentIndex;
653→    const endIndex = startIndex + line.length - 1;
654→
655→    lineIndexRanges.push({
656→      line,
657→      startIndex,
658→      endIndex,
659→      lineNumber,
660→    });
661→
662→    // Move to the next line's start index
663→    currentIndex = endIndex + 1;
664→    lineNumber++;
665→  }
666→
667→  let startIndex = index;
668→  let remainingQuery = textElement.originalText.slice(
669→    index,
670→    index + searchQuery.length,
671→  );
672→  const matchedLines: SearchMatch["matchedLines"] = [];
673→
674→  for (const lineIndexRange of lineIndexRanges) {
675→    if (remainingQuery === "") {
676→      break;
677→    }
678→
679→    if (
680→      startIndex >= lineIndexRange.startIndex &&
681→      startIndex <= lineIndexRange.endIndex
682→    ) {
683→      const matchCapacity = lineIndexRange.endIndex + 1 - startIndex;
684→      const textToStart = lineIndexRange.line.slice(
685→        0,
686→        startIndex - lineIndexRange.startIndex,
687→      );
688→
689→      const matchedWord = remainingQuery.slice(0, matchCapacity);
690→      remainingQuery = remainingQuery.slice(matchCapacity);
691→
692→      const offset = measureText(
693→        textToStart,
694→        getFontString(textElement),
695→        textElement.lineHeight,
696→      );
697→
698→      // measureText returns a non-zero width for the empty string
699→      // which is not what we're after here, hence the check and the correction
700→      if (textToStart === "") {
701→        offset.width = 0;
702→      }
703→
704→      if (textElement.textAlign !== "left" && lineIndexRange.line.length > 0) {
705→        const lineLength = measureText(
706→          lineIndexRange.line,
707→          getFontString(textElement),
708→          textElement.lineHeight,
709→        );
710→
711→        const spaceToStart =
712→          textElement.textAlign === "center"
713→            ? (textElement.width - lineLength.width) / 2
714→            : textElement.width - lineLength.width;
715→        offset.width += spaceToStart;
716→      }
717→
718→      const { width, height } = measureText(
719→        matchedWord,
720→        getFontString(textElement),
721→        textElement.lineHeight,
722→      );
723→
724→      const offsetX = offset.width;
725→      const offsetY = lineIndexRange.lineNumber * offset.height;
726→
727→      matchedLines.push({
728→        offsetX,
729→        offsetY,
730→        width,
731→        height,
732→        showOnCanvas: true,
733→      });
734→
735→      startIndex += matchCapacity;
736→    }
737→  }
738→
739→  return matchedLines;
740→};
741→
742→const getMatchInFrame = (
743→  frame: ExcalidrawFrameLikeElement,
744→  searchQuery: SearchQuery,
745→  index: number,
746→  zoomValue: number,
747→): SearchMatch["matchedLines"] => {
748→  const text = frame.name ?? getDefaultFrameName(frame);
749→  const matchedText = text.slice(index, index + searchQuery.length);
750→
751→  const prefixText = text.slice(0, index);
752→  const font = getFontString({
753→    fontSize: FRAME_STYLE.nameFontSize,
754→    fontFamily: FONT_FAMILY.Assistant,
755→  });
756→
757→  const lineHeight = getLineHeight(FONT_FAMILY.Assistant);
758→
759→  const offset = measureText(prefixText, font, lineHeight);
760→
761→  // Correct non-zero width for empty string
762→  if (prefixText === "") {
763→    offset.width = 0;
764→  }
765→
766→  const matchedMetrics = measureText(matchedText, font, lineHeight);
767→
768→  const offsetX = offset.width;
769→  const offsetY = -offset.height - FRAME_STYLE.strokeWidth;
770→  const width = matchedMetrics.width;
771→
772→  return [
773→    {
774→      offsetX,
775→      offsetY,
776→      width,
777→      height: matchedMetrics.height,
778→      showOnCanvas: offsetX + width <= frame.width * zoomValue,
779→    },
780→  ];
781→};
782→
783→const escapeSpecialCharacters = (string: string) => {
784→  return string.replace(/[.*+?^${}()|[\]\\-]/g, "\\$&");
785→};
786→
787→const handleSearch = debounce(
788→  (
789→    searchQuery: SearchQuery,
790→    app: AppClassProperties,
791→    cb: (matchItems: SearchMatchItem[], focusIndex: number | null) => void,
792→  ) => {
793→    if (!searchQuery || searchQuery === "") {
794→      cb([], null);
795→      return;
796→    }
797→
798→    const elements = app.scene.getNonDeletedElements();
799→    const texts = elements.filter((el) =>
800→      isTextElement(el),
801→    ) as ExcalidrawTextElement[];
802→
803→    const frames = elements.filter((el) =>
804→      isFrameLikeElement(el),
805→    ) as ExcalidrawFrameLikeElement[];
806→
807→    texts.sort((a, b) => a.y - b.y);
808→    frames.sort((a, b) => a.y - b.y);
809→
810→    const textMatches: SearchMatchItem[] = [];
811→
812→    const regex = new RegExp(escapeSpecialCharacters(searchQuery), "gi");
813→
814→    for (const textEl of texts) {
815→      let match = null;
816→      const text = textEl.originalText;
817→
818→      while ((match = regex.exec(text)) !== null) {
819→        const preview = getMatchPreview(text, match.index, searchQuery);
820→        const matchedLines = getMatchedLines(textEl, searchQuery, match.index);
821→
822→        if (matchedLines.length > 0) {
823→          textMatches.push({
824→            element: textEl,
825→            searchQuery,
826→            preview,
827→            index: match.index,
828→            matchedLines,
829→          });
830→        }
831→      }
832→    }
833→
834→    const frameMatches: SearchMatchItem[] = [];
835→
836→    for (const frame of frames) {
837→      let match = null;
838→      const name = frame.name ?? getDefaultFrameName(frame);
839→
840→      while ((match = regex.exec(name)) !== null) {
841→        const preview = getMatchPreview(name, match.index, searchQuery);
842→        const matchedLines = getMatchInFrame(
843→          frame,
844→          searchQuery,
845→          match.index,
846→          app.state.zoom.value,
847→        );
848→
849→        if (matchedLines.length > 0) {
850→          frameMatches.push({
851→            element: frame,
852→            searchQuery,
853→            preview,
854→            index: match.index,
855→            matchedLines,
856→          });
857→        }
858→      }
859→    }
860→
861→    const visibleIds = new Set(
862→      app.visibleElements.map((visibleElement) => visibleElement.id),
863→    );
864→
865→    // putting frame matches first
866→    const matchItems: SearchMatchItem[] = [...frameMatches, ...textMatches];
867→
868→    const focusIndex =
869→      matchItems.findIndex((matchItem) =>
870→        visibleIds.has(matchItem.element.id),
871→      ) ?? null;
872→
873→    cb(matchItems, focusIndex);
874→  },
875→  SEARCH_DEBOUNCE,
876→);
