it("should show 'No matches found' when query has no results", async () => {
  API.setElements([
    API.createElement({ type: "text", text: "hello world" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "zzzznotfound");

  await waitFor(() => {
    const noMatch = document.querySelector(
      '[data-testid="search-no-match"]',
    );
    expect(noMatch).not.toBeNull();
    expect(noMatch?.textContent).toContain("No matches found");
  });
});

